(function(){const D={"P0420":{t:"触媒効率低下",s:"中",d:"触媒の効率が低下しています",f:"O2センサー・触媒交換の可能性",c:"¥50,000〜¥150,000"},"P0300":{t:"ランダム失火",s:"高",d:"エンジンが正常に燃焼していません",f:"点火系・プラグ・コイル点検",c:"¥10,000〜¥50,000"}};function I(){const r=document.getElementById("obd2-dtc-checker");if(!r)return;r.innerHTML='<div class="obd-box"><input class="obd-input" placeholder="例: P0420"><button class="obd-btn">診断する</button><div class="obd-result"></div></div>';const i=r.querySelector(".obd-input"),b=r.querySelector(".obd-btn"),o=r.querySelector(".obd-result");b.onclick=()=>{const k=i.value.trim().toUpperCase(),d=D[k];if(!d){o.innerHTML="該当データがありません";return}o.innerHTML=`<h3>${k}：${d.t}</h3><p><strong>危険度：</strong>${d.s}</p><p>${d.d}</p><p><strong>対応：</strong>${d.f}</p><p><strong>費用目安：</strong>${d.c}</p>`}}document.addEventListener("DOMContentLoaded",I)})();
